import{c as n,S as h,j as t,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Học bài giảng","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/hoc-bai-giang.md","filePath":"hoc-vien/hoc-bai-giang.md","lastUpdated":0}'),o={name:"hoc-vien/hoc-bai-giang.md"};function c(g,i,l,e,r,s){return h(),t("div",null,[...i[0]||(i[0]=[a('<h1 id="hoc-bai-giang" tabindex="-1">Học bài giảng <a class="header-anchor" href="#hoc-bai-giang" aria-label="Permalink to “Học bài giảng”">​</a></h1><p>Trong một khóa học, <strong>bài giảng</strong> là phần để bạn học kiến thức (khác với bài kiểm tra để đánh giá).</p><h2 id="bai-giang-co-nhung-dang-nao" tabindex="-1">Bài giảng có những dạng nào? <a class="header-anchor" href="#bai-giang-co-nhung-dang-nao" aria-label="Permalink to “Bài giảng có những dạng nào?”">​</a></h2><h3 id="_1-video" tabindex="-1">1. Video <a class="header-anchor" href="#_1-video" aria-label="Permalink to “1. Video”">​</a></h3><ul><li>Trình phát có nút Play, Pause, tua, đổi tốc độ (0.5x → 2x), full screen.</li><li>Bên dưới video có <strong>thanh tiến độ</strong> và <strong>chương phụ</strong> (nếu giáo viên chia chapter).</li><li>Có thể <strong>bật phụ đề</strong> (CC) nếu video có.</li></ul><h3 id="_2-van-ban" tabindex="-1">2. Văn bản <a class="header-anchor" href="#_2-van-ban" aria-label="Permalink to “2. Văn bản”">​</a></h3><ul><li>Hiển thị như một bài viết: chữ, ảnh, bảng, công thức toán LaTeX.</li><li>Có thể cuộn để đọc.</li><li>Một số bài cho phép <strong>highlight</strong> đoạn quan trọng (nếu hệ thống hỗ trợ).</li></ul><h3 id="_3-file-pdf" tabindex="-1">3. File / PDF <a class="header-anchor" href="#_3-file-pdf" aria-label="Permalink to “3. File / PDF”">​</a></h3><ul><li>Hiển thị PDF nhúng trong trang.</li><li>Có thể <strong>phóng to</strong>, <strong>trang lẻ/chẵn</strong>, <strong>toàn màn hình</strong>.</li><li>Nếu được phép, có nút <strong>Tải về</strong> ở góc trên.</li></ul><h3 id="_4-mix" tabindex="-1">4. Mix <a class="header-anchor" href="#_4-mix" aria-label="Permalink to “4. Mix”">​</a></h3><ul><li>Video chính ở trên, văn bản tóm tắt + file kèm bên dưới.</li></ul><h2 id="theo-doi-tien-đo-hoc" tabindex="-1">Theo dõi tiến độ học <a class="header-anchor" href="#theo-doi-tien-đo-hoc" aria-label="Permalink to “Theo dõi tiến độ học”">​</a></h2><ul><li>Sau khi xem hết bài (&gt;= 80% video hoặc cuộn hết văn bản), bài tự đánh dấu <strong>Đã hoàn thành</strong>.</li><li>Tỷ lệ hoàn thành cập nhật trong <strong>Khóa học của tôi</strong>.</li><li>Một số khóa yêu cầu xem <strong>đủ 100%</strong> mới đánh dấu hoàn thành.</li></ul><h2 id="chuyen-giua-cac-bai" tabindex="-1">Chuyển giữa các bài <a class="header-anchor" href="#chuyen-giua-cac-bai" aria-label="Permalink to “Chuyển giữa các bài”">​</a></h2><ul><li><strong>Mục lục bên trái</strong>: bấm trực tiếp bài muốn học (nếu chưa bị khóa).</li><li><strong>Nút Bài trước / Bài tiếp</strong> ở dưới trình phát.</li><li><strong>Phím tắt</strong> (tùy hệ thống): <ul><li><code>Space</code> - Play/Pause</li><li><code>←</code> / <code>→</code> - tua 5-10 giây</li><li><code>↑</code> / <code>↓</code> - âm lượng</li><li><code>F</code> - toàn màn hình</li></ul></li></ul><h2 id="ghi-chu-ca-nhan-note" tabindex="-1">Ghi chú cá nhân (Note) <a class="header-anchor" href="#ghi-chu-ca-nhan-note" aria-label="Permalink to “Ghi chú cá nhân (Note)”">​</a></h2><p>Nếu hệ thống hỗ trợ:</p><ul><li>Có ô <strong>Note</strong> bên dưới video.</li><li>Bạn gõ note, hệ thống lưu kèm <strong>timestamp</strong>.</li><li>Sau này click vào note → video nhảy về đúng phút đó.</li></ul><h2 id="đat-cau-hoi-cho-giao-vien" tabindex="-1">Đặt câu hỏi cho giáo viên <a class="header-anchor" href="#đat-cau-hoi-cho-giao-vien" aria-label="Permalink to “Đặt câu hỏi cho giáo viên”">​</a></h2><ul><li>Ngay dưới bài giảng có khung <strong>Hỏi đáp</strong> / <strong>Thảo luận</strong>.</li><li>Gõ câu hỏi → bấm <strong>Gửi</strong>.</li><li>Có thể đính kèm ảnh / file.</li><li>Giáo viên sẽ trả lời (xem chi tiết: <a href="./hoi-dap">Hỏi đáp</a>).</li></ul><h2 id="bai-giang-hoc-thu-mien-phi" tabindex="-1">Bài giảng học thử (miễn phí) <a class="header-anchor" href="#bai-giang-hoc-thu-mien-phi" aria-label="Permalink to “Bài giảng học thử (miễn phí)”">​</a></h2><ul><li>Có icon <strong>🎁 Học thử</strong>.</li><li>Bạn xem miễn phí dù chưa mua khóa.</li><li>Dùng để <strong>đánh giá chất lượng</strong> trước khi mua.</li></ul><h2 id="tai-xuong-bai-giang" tabindex="-1">Tải xuống bài giảng <a class="header-anchor" href="#tai-xuong-bai-giang" aria-label="Permalink to “Tải xuống bài giảng”">​</a></h2><ul><li><strong>Video</strong>: thường KHÔNG cho tải về (bảo vệ bản quyền).</li><li><strong>PDF / Tài liệu kèm</strong>: nếu cho phép, có nút <strong>Tải về</strong>.</li><li>Có thể có app mobile cho phép tải video về xem offline (nếu hệ thống có app).</li></ul><h2 id="meo-hoc-hieu-qua" tabindex="-1">Mẹo học hiệu quả <a class="header-anchor" href="#meo-hoc-hieu-qua" aria-label="Permalink to “Mẹo học hiệu quả”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Học 1 chuyên đề trọn vẹn trong 1 lần</p><p>Đừng học ngắt quãng giữa chuyên đề. Kéo dài tập trung 30-45 phút thay vì nhảy lung tung.</p></div><div class="tip custom-block"><p class="custom-block-title">Ghi chú ngay</p><p>Mở Word/sổ tay ghi lại công thức/ý chính khi xem. Học bằng tay nhớ lâu hơn nghe thụ động.</p></div><div class="tip custom-block"><p class="custom-block-title">Tăng tốc độ video khi đã hiểu phần đó</p><p>Xem 1.25x - 1.5x với những đoạn quen, 0.75x với phần khó. Tận dụng thời gian.</p></div><div class="tip custom-block"><p class="custom-block-title">Làm bài tập ngay sau bài giảng</p><p>Mỗi bài giảng nên kèm 5-10 phút làm bài tập tự luyện hoặc đề kiểm tra cuối chuyên đề - để kiến thức không trôi tuột.</p></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Video bị giật / chậm.</strong> → Đổi chất lượng video xuống 720p / 480p. Hoặc kiểm tra Internet.</p><p><strong>Video không phát, hiện màn hình đen.</strong> → Đảm bảo trình duyệt cập nhật mới. Tắt extension chặn quảng cáo (đôi khi block trình phát). Thử trình duyệt khác.</p><p><strong>Tôi không thể bấm bài tiếp theo dù đã xem hết.</strong> → Có thể bài này yêu cầu hoàn thành cả <strong>bài kiểm tra cuối chuyên đề</strong> với điểm tối thiểu. Quay lại làm bài kiểm tra.</p><p><strong>Bài giảng không có tài liệu kèm?</strong> → Hỏi giáo viên qua <strong>Hỏi đáp</strong> - họ có thể đính file vào.</p><p><strong>Tôi học cùng lúc trên điện thoại và máy tính, tiến độ có đồng bộ không?</strong> → Có. Hệ thống đồng bộ thời gian xem giữa các thiết bị.</p>',35)])])}const p=n(o,[["render",c]]);export{d as __pageData,p as default};
